local xml = require "lxp.lom"
local cjson = require "cjson"

local function parse_xml_request(body)
    if not body or body == "" then
        return nil, "Empty request body"
    end
    
    local parser = xml.new()
    parser:parse(body)
    
    local success, result = pcall(function()
        return xml.parse(body)
    end)
    
    if not success then
        return nil, "XML parsing failed: " .. tostring(result)
    end
    
    return result
end

local function extract_soap_data(parsed_xml)
    local data = {}
    
    if not parsed_xml then
        return data
    end
    
    -- Extract SOAP envelope
    local envelope = parsed_xml[1]
    if not envelope or envelope.tag ~= "Envelope" then
        return data
    end
    
    -- Extract body
    local body = envelope[1]
    if not body or body.tag ~= "Body" then
        return data
    end
    
    -- Extract first child element from body
    local operation = body[1]
    if operation then
        data.operation = operation.tag
        data.namespace = operation.attr and operation.attr.xmlns
        data.params = {}
        
        -- Extract all parameters
        for i, child in ipairs(operation) do
            if child.tag and child.text then
                data.params[child.tag] = child.text
            end
        end
    end
    
    return data
end

local function process_soap_request()
    local request_body = ngx.req.get_body_data()
    
    if not request_body then
        ngx.status = 400
        ngx.say("Bad Request: Empty body")
        ngx.exit(400)
        return
    end
    
    local parsed_xml, err = parse_xml_request(request_body)
    if not parsed_xml then
        ngx.status = 400
        ngx.say("Bad Request: " .. err)
        ngx.exit(400)
        return
    end
    
    local soap_data = extract_soap_data(parsed_xml)
    
    -- Process the extracted data
    ngx.ctx.soap_data = soap_data
    
    return soap_data
end

-- Main execution
local soap_data = process_soap_request()

-- Example usage for further processing
if soap_data and soap_data.operation then
    ngx.log(ngx.INFO, "Processing SOAP operation: " .. soap_data.operation)
    
    -- Add your business logic here
    local response = {
